// packages/core/src/components/client/NavigationDropdown/NavigationDropdown.test.tsx
// Generated by AI (DoXYZ agents). Do not edit directly.
// Summary: Checks NavigationDropdown trigger labeling, icon swap on open, menu item rendering with links, optional aria landmark wrapping, and modal panel class tokens.

import * as React from 'react';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { NavigationDropdown } from './NavigationDropdown';

const minimalItems = [{ label: 'Overview', href: '/overview' }];

describe('NavigationDropdown', () => {
  it('renders the trigger button with the default accessible name', () => {
    render(<NavigationDropdown items={minimalItems} />);

    expect(screen.getByRole('button', { name: 'Menu' })).toBeInTheDocument();
  });

  it('uses triggerAriaLabel when provided, trimming surrounding whitespace', () => {
    render(<NavigationDropdown items={minimalItems} triggerAriaLabel={'  Open navigation  '} />);

    expect(screen.getByRole('button', { name: 'Open navigation' })).toBeInTheDocument();
  });

  it('falls back to "Menu" when triggerAriaLabel is whitespace-only', () => {
    render(<NavigationDropdown items={minimalItems} triggerAriaLabel={'   '} />);

    expect(screen.getByRole('button', { name: 'Menu' })).toBeInTheDocument();
  });

  it('renders the open icon while the popover is closed', () => {
    render(
      <NavigationDropdown
        items={minimalItems}
        openIcon={<span data-testid="open-icon">Open</span>}
        closeIcon={<span data-testid="close-icon">Close</span>}
      />
    );

    expect(screen.getByTestId('open-icon')).toBeInTheDocument();
  });

  it('renders the close icon once the popover opens', async () => {
    render(
      <NavigationDropdown
        items={minimalItems}
        openIcon={<span data-testid="open-icon">Open</span>}
        closeIcon={<span data-testid="close-icon">Close</span>}
      />
    );
    const user = userEvent.setup();

    await user.click(screen.getByRole('button', { name: 'Menu' }));

    expect(await screen.findByTestId('close-icon')).toBeInTheDocument();
  });

  it('renders each item as a link with the expected label and href', async () => {
    const items = [
      { label: 'Overview', href: '/overview' },
      { label: 'Billing', href: '/billing', ariaLabel: 'Billing and payments' },
      { label: 'Support', href: '/support' }
    ];
    render(<NavigationDropdown items={items} />);
    const user = userEvent.setup();
    await user.click(screen.getByRole('button', { name: 'Menu' }));

    const actual = (await screen.findAllByRole('link')).map(link => ({
      href: link.getAttribute('href'),
      text: link.textContent?.trim()
    }));

    expect(actual).toEqual(
      items.map(item => ({
        href: item.href,
        text: item.label
      }))
    );
  });

  it('wraps the list in a navigation landmark when ariaLabel is provided', async () => {
    render(<NavigationDropdown items={minimalItems} ariaLabel="Primary navigation" />);
    const user = userEvent.setup();
    await user.click(screen.getByRole('button', { name: 'Menu' }));

    expect(
      await screen.findByRole('navigation', { name: 'Primary navigation' })
    ).toBeInTheDocument();
  });

  it('applies the modal panel layout classes', async () => {
    render(<NavigationDropdown items={minimalItems} />);
    const user = userEvent.setup();
    await user.click(screen.getByRole('button', { name: 'Menu' }));

    const panel = await screen.findByTestId('navigation-dropdown-panel');

    expect(panel.className).toContain(
      'z-50 py-4 bg-background-none w-screen h-screen top-[var(--nav-offset)] overflow-y-auto'
    );
  });
});
